#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
int t, h;
bool p[MAXN];

void primes() {
    for (int i = 2; i <= MAXN; i++) {
        if (!p[i]) {
            for (int j = 2 * i; j <= MAXN; j += i) {
                p[j] = true;
            }
        }
    }
}

int main() {
    p[0] = p[1] = true;
    primes();
    cin >> t;
    for (int i = 0; i < t; i++) {
        int h;
        cin >> h;
        if (!p[h]) {
            cout << 1 << endl;
            continue;
        }
        for (int j = 1; ; j++) {
            h -= 1 << (j - 1);
            if (h < 0) {
                cout << "-1\n";
                break;
            }
            if (!p[h]) {
                cout << j + 1 << endl;
                break;
            }
            if (h == 0) {
                cout << j << endl;
                break;
            }
        }
    }
    return 0;
}
